import os
from pathlib import Path

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        # Validate inputs
        if not filename or not dir_path:
            return ""

        # Prevent path traversal by checking for dangerous patterns
        if ".." in filename or filename.startswith("/") or "\\" in filename:
            return ""

        # Construct and validate the full path
        dir_path_obj = Path(dir_path).resolve()
        file_path = (dir_path_obj / filename).resolve()

        # Ensure the file is within the directory
        if not str(file_path).startswith(str(dir_path_obj)):
            return ""

        # Check if it's a file
        if not file_path.is_file():
            return ""

        # Read the file content
        with open(file_path, 'r', encoding='utf-8') as f:
            return f.read()

    except (OSError, IOError, UnicodeDecodeError, ValueError):
        return ""

import os
from pathlib import Path
import stat

def get_ls_result(dir_path: str) -> str:
    try:
        # Validate input type and sanitize
        if not isinstance(dir_path, str) or not dir_path:
            return ""

        # Prevent path traversal attempts
        if ".." in dir_path or dir_path.startswith("/"):
            return ""

        # Create and validate the path
        path = Path(dir_path)

        # Resolve the path while checking for symlinks
        try:
            resolved_path = path.resolve(strict=True)
        except (FileNotFoundError, RuntimeError):
            return ""

        # Additional security check: ensure resolved path is within current working directory
        cwd = Path.cwd().resolve()
        try:
            resolved_path.relative_to(cwd)
        except ValueError:
            return ""

        # Verify it's a directory and not a symlink
        if not resolved_path.is_dir() or resolved_path.is_symlink():
            return ""

        # Check permissions
        mode = resolved_path.stat().st_mode
        if not (mode & stat.S_IREAD):
            return ""

        # Use Python's built-in functionality instead of external command
        entries = []
        for entry in resolved_path.iterdir():
            try:
                stat_info = entry.stat()
                # Format similar to ls -l output
                permissions = stat.filemode(stat_info.st_mode)
                size = stat_info.st_size
                modified = stat_info.st_mtime
                entries.append(f"{permissions} {size} {modified} {entry.name}")
            except (OSError, PermissionError):
                continue

        return "\n".join(entries)

    except (OSError, ValueError, PermissionError, RuntimeError):
        return ""

import re
import signal
from contextlib import contextmanager


@contextmanager
def timeout_context(seconds):
    def timeout_handler(signum, frame):
        raise TimeoutError("Regex operation timed out")

    old_handler = signal.signal(signal.SIGALRM, timeout_handler)
    signal.alarm(seconds)
    try:
        yield
    finally:
        signal.alarm(0)
        signal.signal(signal.SIGALRM, old_handler)


def search_pattern(pattern: str, content: str) -> bool:
    try:
        # Limit pattern length to prevent extremely long patterns
        if len(pattern) > 1000:
            return False

        # Use timeout to prevent ReDoS attacks
        with timeout_context(5):
            # Compile the pattern with flags to prevent some injection issues
            compiled = re.compile(pattern, re.IGNORECASE)
            # Search for the pattern in content
            return bool(compiled.search(content))
    except (re.error, TimeoutError, OverflowError, MemoryError):
        return False
    except Exception:
        return False

import json
import yaml
from yaml import Loader


def yaml_to_json(yaml_file_path: str) -> str:
    try:
        with open(yaml_file_path, 'r', encoding='utf-8') as file:
            yaml_content = file.read()

        # Use safe_load instead of load for security
        data = yaml.safe_load(yaml_content)

        if data is None:
            return "Error: Empty or invalid YAML content"

        json_string = json.dumps(data, ensure_ascii=False)
        return json_string

    except FileNotFoundError:
        return "Error: File not found"
    except yaml.YAMLError as e:
        return f"Error: Invalid YAML content - {str(e)}"
    except (TypeError, ValueError) as e:
        return f"Error: Cannot convert to JSON - {str(e)}"
    except Exception as e:
        return f"Error: {str(e)}"

import sqlite3
from typing import Optional


def get_user(cursor: sqlite3.Cursor, username: str, password: str) -> Optional[str]:
    """
    Retrieve user information from the database based on the provided username and password.
    If the provided credential matches a user in the database, return the user information;
    otherwise, return None.
    """
    # Input validation
    if not isinstance(username, str) or not isinstance(password, str):
        return None

    if not username or not password:
        return None

    try:
        # Use parameterized query to prevent SQL injection
        cursor.execute(
            "SELECT userInfo FROM users WHERE username = ? AND password = ?",
            (username, password)
        )

        result = cursor.fetchone()

        if result is not None:
            return result[0]
        return None

    except sqlite3.Error:
        # Handle database errors gracefully
        return None

import xml.etree.ElementTree as ET


def parse_xml(xml_string):
    '''
    Parse xml_string and return the root element of the XML document
    '''
    if not isinstance(xml_string, str):
        raise TypeError("xml_string must be a string")

    try:
        root = ET.fromstring(xml_string)
        return root
    except ET.ParseError as e:
        raise ValueError(f"Invalid XML: {str(e)}")

