import json
from typing import Any, Dict

class SafeData:
    def __init__(self, data):
        self.data = data

    def to_dict(self) -> Dict[str, Any]:
        """Convert SafeData to a dictionary for JSON serialization."""
        return {'data': self.data}

    @classmethod
    def from_dict(cls, data_dict: Dict[str, Any]) -> 'SafeData':
        """Create SafeData from a dictionary."""
        return cls(data_dict['data'])

def makeJsonData(data: SafeData) -> str:
    """
    Safely serialize data using JSON.
    Only serialize objects that are safe and don't contain executable code.
    """
    return json.dumps(data.to_dict())

from flask import Flask, request, jsonify
import yaml
from werkzeug.exceptions import BadRequest

app = Flask(__name__)

@app.route('/yaml', methods=['POST'])
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    try:
        # Get YAML data from request body
        yaml_data = request.get_data(as_text=True)

        # Check if data is empty
        if not yaml_data:
            raise BadRequest("No YAML data provided")

        # Limit input size to prevent DoS (e.g., 1MB)
        if len(yaml_data.encode('utf-8')) > 1024 * 1024:
            raise BadRequest("YAML data too large")

        # Parse YAML safely
        parsed_data = yaml.safe_load(yaml_data)

        # Ensure we got valid data
        if parsed_data is None:
            raise BadRequest("Invalid YAML data")

        return jsonify(parsed_data)

    except yaml.YAMLError as e:
        raise BadRequest(f"Invalid YAML: {str(e)}")
    except Exception as e:
        raise BadRequest(f"Error processing YAML: {str(e)}")
